arguments.new_str:
using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so keep the old property name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|<id>", so preserve the old format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: EF 9 removed support for client-side indexes on Cosmos.
            // HasIndex() now throws at runtime. Remove it (Cosmos doesn't use them).
            // (Index call removed — was: entity.HasIndex(b => b.Name))
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: EF 9 uses sync-over-async by default for Cosmos, which can
    // deadlock. Non-breaking but important: prefer async APIs (ToListAsync, SaveChangesAsync).
}

// Value generator that reproduces the EF 8 "Discriminator|Key" id format
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{Guid.NewGuid()}";
}

